def common(a, b):
    # SLOW: 'x in b' scans the list b (O(n)) for every x in a (O(n)) -> O(n*m).
    # Rewrite using a set so each lookup is O(1), making this O(n + m).
    # Keep the output identical: sorted, no duplicates.
    result = []
    for x in a:
        if x in b and x not in result:   # O(n) scan + O(n) scan -> quadratic
            result.append(x)
    return sorted(result)

print(common([3, 1, 2, 2, 5], [2, 5, 5, 8]))
